// ── Template config ──
// cx, cy, r: circle center and radius in template pixel coordinates
// W, H: template natural size
// nameY, deptY: text positions
// style: 'dark' | 'light-warm' | 'light-pastel'
const TEMPLATES = {
  t1: { W:1254, H:1254, cx:628, cy:742, r:320, nameY:1130, deptY:1200, style:'dark',  b64: 'data:image/png;base64,' },
  t3: { W:1254, H:1254, cx:626, cy:765, r:325, nameY:1140, deptY:1200, style:'pastel',b64: 'data:image/png;base64,' },
};

// ── State ──
let activeTemplate = 't1';
let userPhoto = null;
const loadedImgs = {};
const SCRIPT_URL = "https://script.google.com/macros/s/AKfycbyYKJKO-PtBlCzxeHQlxt5Q6hfE6hPSw8WKsTThg3t9pF4O1k0Gtr_LHWN1pbs4dvxl/exec";
// ── Load all template images ──
Object.entries(TEMPLATES).forEach(([key, cfg]) => {
  const img = new Image();
  img.onload = () => {
    loadedImgs[key] = img;
    document.getElementById('thumb-' + key).src = cfg.b64;
    if (key === 't1') drawInitial();
  };
  img.src = cfg.b64;
});

function selectTemplate(key) {
  activeTemplate = key;
  document.querySelectorAll('.tmpl-card').forEach(c => c.classList.remove('active'));
  document.querySelector(`[data-tmpl="${key}"]`).classList.add('active');
  document.getElementById('downloadBtn').disabled = true;
  drawInitial();
}

function drawInitial() {
  const cfg = TEMPLATES[activeTemplate];
  const img = loadedImgs[activeTemplate];
  if (!img) return;
  const canvas = document.getElementById('posterCanvas');
  canvas.width  = cfg.W;
  canvas.height = cfg.H;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(img, 0, 0, cfg.W, cfg.H);
  // Blank placeholder
  ctx.save();
  ctx.beginPath();
  ctx.arc(cfg.cx, cfg.cy, cfg.r - 6, 0, Math.PI * 2);
  ctx.fillStyle = cfg.style === 'dark' ? '#c8cdd4' : '#d4d6d8';
  ctx.fill();
  ctx.restore();
  // Hint text
  ctx.save();
  ctx.font = `bold 26px Segoe UI, system-ui, sans-serif`;
  ctx.fillStyle = cfg.style === 'dark' ? '#8a9aaa' : '#9aaabb';
  ctx.textAlign = 'center';
  ctx.fillText('Upload your photo', cfg.cx, cfg.cy - 10);
  ctx.font = '20px Segoe UI, system-ui, sans-serif';
  ctx.fillText('and click Generate', cfg.cx, cfg.cy + 28);
  ctx.restore();
}

// ── Photo upload ──
document.getElementById('photoInput').addEventListener('change', function(e) {
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (ev) => {
    const img = new Image();
    img.onload = () => {
      userPhoto = img;
      const thumb = document.getElementById('photoThumb');
      thumb.src = ev.target.result;
      thumb.style.display = 'block';
      document.getElementById('uploadContent').style.display = 'none';
    };
    img.src = ev.target.result;
  };
  reader.readAsDataURL(file);
});

// ── Generate ──
function generatePoster() {
  const cfg = TEMPLATES[activeTemplate];
  const bgImg = loadedImgs[activeTemplate];
  if (!bgImg)     { alert('Template is still loading, please wait.'); return; }
  if (!userPhoto) { alert('Please upload your portrait photo first.'); return; }
  const name = document.getElementById('nameInput').value.trim();
  const dept = document.getElementById('deptSelect').value;
  if (!name) { alert('Please enter your full name.'); return; }
  if (!dept) { alert('Please select your department.'); return; }

  const canvas = document.getElementById('posterCanvas');
  canvas.width  = cfg.W;
  canvas.height = cfg.H;
  const ctx = canvas.getContext('2d');

  // 1. Background
  ctx.drawImage(bgImg, 0, 0, cfg.W, cfg.H);

  // 2. Clip photo into circle
  ctx.save();
  ctx.beginPath();
  ctx.arc(cfg.cx, cfg.cy, cfg.r - 5, 0, Math.PI * 2);
  ctx.clip();
  ctx.fillStyle = '#d0d2d6';
  ctx.fillRect(cfg.cx - cfg.r, cfg.cy - cfg.r, cfg.r * 2, cfg.r * 2);
  const pW = userPhoto.naturalWidth  || userPhoto.width;
  const pH = userPhoto.naturalHeight || userPhoto.height;
  const diam = (cfg.r - 5) * 2;
  const scale = Math.max(diam / pW, diam / pH);
  ctx.drawImage(userPhoto, cfg.cx - pW*scale/2, cfg.cy - pH*scale/2, pW*scale, pH*scale);
  ctx.restore();

  // 3. Text
  drawNameLabel(ctx, name, cfg);
  drawDeptLabel(ctx, dept, cfg);

  document.getElementById('downloadBtn').disabled = false;
  document.getElementById('uploadBtn').disabled = false;
}

// ── Name with ornament lines ──
function drawNameLabel(ctx, name, cfg) {
  const cx = cfg.W / 2;
  const y  = cfg.nameY;
  const isDark   = cfg.style === 'dark';
  const isWarm   = cfg.style === 'warm';
  const isPastel = cfg.style === 'pastel';

  ctx.save();
  ctx.font = `bold 50px Georgia, "Times New Roman", serif`;
  const textW = ctx.measureText(name).width;
  const gap    = 20;
  const lineW  = Math.max(55, (cfg.W * 0.70 - textW) / 2 - gap);
  const lineY  = y - 15;

  // Color scheme
  const lineColor = isDark ? '#f0c040' : isWarm ? '#b8861a' : '#7a4ab0';
  const glowColor = isDark ? '#ffe066' : isWarm ? '#e0a820' : '#c090e0';
  const textColor = isDark ? '#ffffff'  : isWarm ? '#0d1e3c' : '#2a1060';
  const textGlow  = isDark ? '#ffe590' : isWarm ? '#c09030' : '#a070d0';

  ctx.shadowColor = glowColor;
  ctx.shadowBlur  = isDark ? 24 : 10;
  ctx.strokeStyle = lineColor;
  ctx.lineWidth   = isDark ? 3 : 2.5;

  const lx2 = cx - textW/2 - gap;
  drawOrnamentLine(ctx, lx2 - lineW, lx2, lineY, 'left', lineColor, glowColor, isDark);
  const rx1 = cx + textW/2 + gap;
  drawOrnamentLine(ctx, rx1, rx1 + lineW, lineY, 'right', lineColor, glowColor, isDark);

  ctx.shadowColor  = textGlow;
  ctx.shadowBlur   = isDark ? 28 : 8;
  ctx.fillStyle    = textColor;
  ctx.textAlign    = 'center';
  ctx.fillText(name, cx, y);
  ctx.restore();
}

function drawOrnamentLine(ctx, x1, x2, y, side, color, glow, isDark) {
  const ds = 9;
  ctx.shadowColor = glow;
  ctx.shadowBlur  = isDark ? 20 : 8;
  ctx.beginPath();
  ctx.moveTo(x1, y);
  ctx.lineTo(x2, y);
  ctx.stroke();
  const dx = side === 'left' ? x2 : x1;
  ctx.save();
  ctx.translate(dx, y);
  ctx.rotate(Math.PI / 4);
  ctx.fillStyle   = color;
  ctx.shadowColor = glow;
  ctx.shadowBlur  = isDark ? 18 : 8;
  ctx.fillRect(-ds/2, -ds/2, ds, ds);
  ctx.restore();
}

// ── Department pill/badge ──
function drawDeptLabel(ctx, dept, cfg) {
  const cx       = cfg.W / 2;
  const y        = cfg.deptY;
  const isDark   = cfg.style === 'dark';
  const isWarm   = cfg.style === 'warm';
  const isPastel = cfg.style === 'pastel';
  const fontSize = 32;

  ctx.save();
  ctx.font = `600 ${fontSize}px 'Segoe UI', system-ui, sans-serif`;
  const textW = ctx.measureText(dept).width;
  const padX  = 36, padY = 16;
  const boxW  = textW + padX * 2;
  const boxH  = fontSize + padY * 2;
  const boxX  = cx - boxW / 2;
  const boxY  = y - fontSize - padY + 4;
  const r     = boxH / 2;

  const borderColor = isDark ? '#4dbfff' : isWarm ? '#1a3a7a' : '#9060c0';
  const glowColor   = isDark ? '#4dbfff' : isWarm ? '#3a6aaa' : '#c090e0';
  const fillColor   = isDark ? 'rgba(4,18,50,0.72)' : isWarm ? 'rgba(240,244,255,0.80)' : 'rgba(248,240,255,0.80)';
  const textColor   = isDark ? '#d0f0ff' : isWarm ? '#0d1e4a' : '#3a1080';

  // Glow + border
  ctx.shadowColor = glowColor;
  ctx.shadowBlur  = isDark ? 28 : 12;
  ctx.beginPath();
  ctx.roundRect(boxX, boxY, boxW, boxH, r);
  ctx.strokeStyle = borderColor;
  ctx.lineWidth   = 2.5;
  ctx.stroke();

  // Fill
  ctx.shadowBlur = 0;
  ctx.fillStyle  = fillColor;
  ctx.fill();

  // Text
  ctx.shadowColor   = glowColor;
  ctx.shadowBlur    = isDark ? 14 : 6;
  ctx.fillStyle     = textColor;
  ctx.textAlign     = 'center';
  ctx.textBaseline  = 'middle';
  ctx.fillText(dept, cx, boxY + boxH / 2);
  ctx.restore();
}

// ── Download ──
function downloadPoster() {
  const canvas = document.getElementById('posterCanvas');
  const link   = document.createElement('a');
  const name   = document.getElementById('nameInput').value.trim().replace(/\s+/g, '_') || 'graduate';
  const tmpl   = activeTemplate.toUpperCase();
  link.download = `Senior2027_FCAICU_${tmpl}_${name}.png`;
  link.href     = canvas.toDataURL('image/png', 1.0);
  link.click();
}

function togglePrompt() {
    const content = document.getElementById("helpContent");
    const arrow = document.getElementById("promptArrow");

    content.classList.toggle("open");
    arrow.textContent = content.classList.contains("open") ? "▲" : "▼";
}

function copyPrompt() {
    const text = document.getElementById("promptText").innerText;

    navigator.clipboard.writeText(text).then(() => {
        alert("Prompt copied!");
    });
}
async function submitPoster() {
    const canvas = document.getElementById("posterCanvas");

    const name = document.getElementById("nameInput").value;
    const department = document.getElementById("deptSelect").value;

    const imageData = canvas
        .toDataURL("image/jpeg", 0.8)
        .split(",")[1];

    const payload = {
        name,
        department,
        image: imageData
    };

    try {
        const response = await fetch(SCRIPT_URL, {
            method: "POST",
            mode: "no-cors",
            body: JSON.stringify(payload)
        });

        if (response){
          alert("The Poster Sent Successfully");
        }
    } catch (err) {
        console.error("Fetch Error:", err);
    }
}